import 'package:flutter/material.dart';import '../../services/import_check_service.dart';class ImportCheckPage extends StatefulWidget{const ImportCheckPage({super.key});@override State<ImportCheckPage> createState()=>_ImportCheckPageState();}class _ImportCheckPageState extends State<ImportCheckPage>{final controller=TextEditingController();String? resultText;@override void dispose(){controller.dispose();super.dispose();}@override Widget build(BuildContext context)=>Scaffold(appBar:AppBar(title:const Text('Import Check')),body:ListView(padding:const EdgeInsets.all(16),children:[const Card(child:ListTile(leading:Icon(Icons.fact_check_outlined),title:Text('Import check'),subtitle:Text('Validates bundle shape before any future import flow.'))),TextField(controller:controller,minLines:6,maxLines:12,decoration:const InputDecoration(border:OutlineInputBorder(),labelText:'Paste bundle JSON')),const SizedBox(height:8),FilledButton.icon(onPressed:(){final r=ImportCheckService().check(controller.text);setState(()=>resultText='ok=${r.ok}\n${r.messages.join('\n')}\n${r.warnings.join('\n')}');},icon:const Icon(Icons.check),label:const Text('Check')),if(resultText!=null)Card(child:ListTile(title:const Text('Result'),subtitle:Text(resultText!)))]));}
